class SocialLoginManager(private val context: Context) {
    private val facebookCallbackManager = CallbackManager.Factory.create()
    private var googleSignInClient: GoogleSignInClient? = null

    init {
        setupGoogleSignIn()
    }

    private fun setupGoogleSignIn() {
        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            .requestEmail()
            .requestIdToken("1234-abcdef.apps.googleusercontent.com")
            .build()
        googleSignInClient = GoogleSignIn.getClient(context, gso)
    }

    fun signInWithFacebook(activity: AppCompatActivity, callback: (Result<String>) -> Unit) {
        val loginManager = LoginManager.getInstance()
        loginManager.logInWithReadPermissions(activity, Arrays.asList("public_profile", "email"))
        loginManager.registerCallback(facebookCallbackManager, object : FacebookCallback<LoginResult> {
            override fun onSuccess(result: LoginResult) {
                callback(Result.success("Facebook login successful"))
            }

            override fun onCancel() {
                callback(Result.failure(Exception("Facebook login cancelled")))
            }

            override fun onError(error: FacebookException) {
                callback(Result.failure(error))
            }
        })
    }

    fun signInWithGoogle(activity: AppCompatActivity, callback: (Result<String>) -> Unit) {
        val signInIntent = googleSignInClient?.signInIntent
        activity.startActivityForResult(signInIntent, RC_GOOGLE_SIGN_IN)
        googleSignInCallback = callback
    }

    fun handleFacebookResult(requestCode: Int, resultCode: Int, data: Intent?): Boolean {
        return facebookCallbackManager.onActivityResult(requestCode, resultCode, data)
    }

    private var googleSignInCallback: ((Result<String>) -> Unit)? = null

    fun handleGoogleResult(requestCode: Int, resultCode: Int, data: Intent?): Boolean {
        if (requestCode == RC_GOOGLE_SIGN_IN) {
            val task: Task<GoogleSignInAccount> = GoogleSignIn.getSignedInAccountFromIntent(data)
            try {
                val account = task.getResult(ApiException::class.java)
                if (account != null) {
                    googleSignInCallback?.invoke(Result.success("Google login successful"))
                }
            } catch (e: ApiException) {
                googleSignInCallback?.invoke(Result.failure(e))
            }
            return true
        }
        return false
    }

    companion object {
        private const val RC_GOOGLE_SIGN_IN = 9001
    }
}

